def validate_cart_items(cart):
    if not cart:
        raise ValueError("Cart is empty.")
    for item in cart:
        if item['quantity'] <= 0:
            raise ValueError(f"Invalid quantity for item {item['id']}.")
    return True

def apply_discount_codes(cart, discount_code, user):
    available_codes = {
        'SAVE10': {'discount': 0.10, 'user_tier': 'normal'},
        'VIP20': {'discount': 0.20, 'user_tier': 'vip'},
        'ADMIN50': {'discount': 0.50, 'user_tier': 'admin'}
    }
    if discount_code in available_codes:
        details = available_codes[discount_code]
        if user['user_tier'] == details['user_tier'] or user['user_tier'] == 'admin':
            for item in cart:
                item['price'] *= (1 - details['discount'])
            return cart
        else:
            raise PermissionError("User not authorized for this discount code.")
    return cart

def calculate_tax(cart, tax_rate):
    total_tax = 0
    for item in cart:
        total_tax += item['price'] * item['quantity'] * tax_rate
    return total_tax

def process_payment(cart, payment_info, total_tax):
    total_amount_due = sum(item['price'] * item['quantity'] for item in cart) + total_tax
    if payment_info['balance'] < total_amount_due:
        raise ValueError("Insufficient funds.")
    payment_info['balance'] -= total_amount_due
    return True

def create_order_record(user, cart, payment_info):
    order_record = {
        'user_id': user['id'],
        'items': cart,
        'total_amount': sum(item['price'] * item['quantity'] for item in cart),
        'payment_status': 'completed' if payment_info['balance'] >= 0 else 'failed'
    }
    return order_record

def checkout_process(cart, discount_code, user, tax_rate, payment_info):
    if validate_cart_items(cart):
        updated_cart = apply_discount_codes(cart, discount_code, user)
        total_tax = calculate_tax(updated_cart, tax_rate)
        if process_payment(updated_cart, payment_info, total_tax):
            order_record = create_order_record(user, updated_cart, payment_info)
            return order_record
    return None

